class Solution {
public:
    int minimumLength(string s) {
        int left = 0, right = s.size() - 1;
        while (left < right) {
            char ch = s[left];
            if (s[right] != ch) break;
            while (left <= right && s[left] == ch) left++;
            while (left <= right && s[right] == ch) right--;
        }
        return right - left + 1;
    }
};
